  ? ($json.choices[0].message.content || $json.choices[0].message.reasoning_content || '')
  : '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
const jsonMatch = content.match(/\{[\s\S]*\}/);
let review;
try {
  review = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  review = { final_quality: 0, summary: 'Final review parse failed', suggestions: [] };
}

const staticData = $getWorkflowStaticData('global');
staticData._finalReview = review;

// Send callback to Forge
try {
