import React from 'react';
import './index.css';
import { useGameLogic } from './hooks/useGameLogic';
import CookieButton from './components/CookieButton';
import FloatingNumber from './components/FloatingNumber';
import GameHeader from './components/GameHeader';
import GameFooter from './components/GameFooter';
import { saveGame } from './utils/storage';

function App() {
  const {
    score,
    buildings,
    elapsedSeconds,
    buyBuilding,
    handleClick,
    floatingNumbers,
    cookiesPerSecond,
    spawnFloatingNumber,
    isPulsing,
    isSaving
  } = useGameLogic();

  // Auto-save every 5 seconds
  const savePayload = React.useRef({ totalCookies: score, buildings });

  React.useEffect(() => {
    savePayload.current = { totalCookies: score, buildings };
  }, [score, buildings]);

  React.useEffect(() => {
    const intervalId = setInterval(() => {
      saveGame(savePayload.current);
    }, 5000);

    return () => clearInterval(intervalId);
  }, []);

  return (
    <div className="app-container">
      <GameHeader score={score} CPS={cookiesPerSecond} isPulsing={isPulsing} isSaving={isSaving} />
      <main className="center-content">
        <CookieButton onCookieClick={(x, y, val) => { handleClick(); spawnFloatingNumber(x, y, val); }} />
        {floatingNumbers.map((number) => (
          <FloatingNumber
            key={number.id}
            value={number.value}
            x={number.x}
            y={number.y}
            drift={number.drift}
            color={number.color}
          />
        ))}
      </main>
      <GameFooter 
        elapsedSeconds={elapsedSeconds} 
        buildings={buildings} 
        buyBuilding={buyBuilding} 
        currentScore={score}
      />
    </div>
  );
}

export default App;

import React, { useState } from 'react';

const CookieButton = ({ onCookieClick }) => {
  const [isRotated, setIsRotated] = useState(false);

  const handleClick = (e) => {
    // Capture mouse coordinates and pass them along with click value
    const x = e.clientX;
    const y = e.clientY;
    const clickValue = 1; // Default click value

    // Trigger rotation animation
    setIsRotated(true);

    // Reset rotation after animation completes (300ms transition)
    setTimeout(() => {
      setIsRotated(false);
    }, 300);

    // Pass coordinates and click value to parent function
    onCookieClick(x, y, clickValue);
  };

  return (
    <div className="cookie-container">
      <button 
        className={`cookie-button ${isRotated ? 'rotated' : ''}`}
        onClick={handleClick}
        aria-label="Cookie button"
        style={{
          transition: 'transform 0.3s ease-out'
        }}
      >
        {/* Cookie image with emoji */}
        <div className="cookie-image">🍪</div>
      </button>
    </div>
  );
};

export default CookieButton;

import React, { useRef } from 'react';

const FloatingNumber = ({ value, x, y, drift, color }) => {
  const isMounted = useRef(true);

  // Cleanup on unmount
  React.useEffect(() => {
    return () => {
      isMounted.current = false;
    };
  }, []);

  return (
    <div
      className="floating-number"
      style={{
        left: `${x}px`,
        top: `${y}px`,
        position: 'absolute',
        pointerEvents: 'none',
        userSelect: 'none',
      }}
    >
      <span
        style={{
          color: color,
          marginLeft: `${drift}px`,
          display: 'inline-block',
        }}
      >
        +{value}
      </span>
    </div>
  );
};

export default FloatingNumber;

import React from 'react';
import { formatNumber, formatTime } from '../utils/formatNumber';

const GameFooter = ({ elapsedSeconds, buildings, buyBuilding, currentScore }) => {
  // Calculate dynamic next rank target using powers of ten
  const nextRankTarget = Math.pow(10, Math.floor(Math.log10(currentScore)) + 1);

  // Calculate progress percentage based on dynamic target
  const progressPercent = nextRankTarget > 0 ? (currentScore / nextRankTarget) * 100 : 0;

  return (
    <div className="game-footer">
      <div className="progress-bar-container">
        <div 
          className="progress-bar" 
          style={{ width: `${Math.min(progressPercent, 100)}%` }}
        />
      </div>
      <div className="timer">{formatTime(elapsedSeconds)}</div>
      <div className="shop">
        {buildings.map((building) => (
          <button 
            key={building.id} 
            className="shop-button"
            onClick={() => buyBuilding(building.id)}
            disabled={currentScore < building.cost}
            style={{
              opacity: currentScore >= building.cost ? 1 : 0.5,
              cursor: currentScore >= building.cost ? 'pointer' : 'not-allowed'
            }}
          >
            {building.name} - {formatNumber(building.cost)} cookies
          </button>
        ))}
      </div>
    </div>
  );
};

export default GameFooter;

import React from 'react';

const GameHeader = ({ score, CPS = 0, isPulsing, isSaving }) => {
  return (
    <div className="game-header">
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
        <h1 
          style={{ 
            fontSize: '3rem', 
            color: 'white', 
            marginBottom: '8px',
            transition: 'transform 0.2s ease'
          }}
          className={isPulsing ? 'pulse-active' : ''}
        >
          {score.toLocaleString()}
        </h1>

        {/* Auto-save indicator - disk icon */}
        {isSaving && (
          <span style={{ 
            fontSize: '1.2rem', 
            color: '#4CAF50',
            animation: 'pulse 1s ease-in-out'
          }}>
            💾
          </span>
        )}
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
        <svg 
          width="20" 
          height="20" 
          viewBox="0 0 24 24" 
          fill="gold"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z"/>
        </svg>
        <span style={{ color: 'gold', fontSize: '1rem' }}>
          {CPS.toFixed(1)} CPS
        </span>
      </div>
    </div>
  );
};

export default GameHeader;

import { useState, useEffect, useRef } from 'react';
import { loadGame, saveGame } from '../utils/storage';

export function useGameLogic() {
  const [totalCookies, setTotalCookies] = useState(0);
  const [clickValue, setClickValue] = useState(1);
  const [floatingNumbers, setFloatingNumbers] = useState([]);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Initialize buildings state
  const [buildings, setBuildings] = useState([
    { id: 1, name: 'Cursor', cost: 15, count: 0, cps: 0.1 },
    { id: 2, name: 'Grandma', cost: 100, count: 0, cps: 1 },
    { id: 3, name: 'Farm', cost: 1100, count: 0, cps: 8 },
  ]);

  // Timer feature
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  // useRef to track current score synchronously
  const currentScoreRef = useRef(totalCookies);
  const isMounted = useRef(true);

  useEffect(() => {
    currentScoreRef.current = totalCookies;
  }, [totalCookies]);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setElapsedSeconds(prev => prev + 1);
    }, 1000);

    return () => clearInterval(intervalId);
  }, []);

  // Derive cookiesPerSecond from buildings array
  const cookiesPerSecond = buildings.reduce((total, building) => {
    return total + (building.count * building.cps);
  }, 0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setTotalCookies(prev => prev + cookiesPerSecond);

      // Track CPS gains for visual feedback
      if (cookiesPerSecond > 0) {
        setIsPulsing(true);
        setTimeout(() => {
          setIsPulsing(false);
        }, 500);
      }
    }, 1000);

    return () => clearInterval(intervalId);
  }, [cookiesPerSecond]);

  // Load saved game state on mount
  useEffect(() => {
    const savedState = loadGame();
    setTotalCookies(savedState.totalCookies || 0);
    setBuildings(savedState.buildings || [
      { id: 1, name: 'Cursor', cost: 15, count: 0, cps: 0.1 },
      { id: 2, name: 'Grandma', cost: 100, count: 0, cps: 1 },
      { id: 3, name: 'Farm', cost: 1100, count: 0, cps: 8 },
    ]);
  }, []);

  const increment = (amount = 1) => {
    setTotalCookies(prev => prev + amount);
  };

  const handleClick = () => {
    increment(clickValue);
  };

  const buyBuilding = (buildingId) => {
    const building = buildings.find(b => b.id === buildingId);

    if (!building) return;

    // Use ref value for affordability check to prevent race condition
    if (currentScoreRef.current < building.cost) {
      return;
    }

    // Deduct cost from score
    setTotalCookies(prev => prev - building.cost);

    // Update building count
    setBuildings(prevBuildings =>
      prevBuildings.map(b =>
        b.id === buildingId
          ? { ...b, count: b.count + 1, cost: Math.floor(b.cost * 1.15) }
          : b
      )
    );

    // Trigger auto-save after purchase
    triggerAutoSave();
  };

  const spawnFloatingNumber = (x, y, value) => {
    if (!isMounted.current) return;

    // Add random drift between -30 and 30 pixels
    const drift = Math.random() * 60 - 30;

    const id = Math.random().toString(36).substr(2);

    // Generate random color for floating number
    const color = Math.random() > 0.5 ? 'gold' : 'white';

    const newNumber = {
      id,
      value,
      x,
      y,
      color,
      drift,
    };

    setFloatingNumbers(prev => [...prev, newNumber]);

    // Remove after animation completes
    setTimeout(() => {
      if (isMounted.current) {
        setFloatingNumbers(prev => prev.filter(num => num.id !== newNumber.id));
      }
    }, 1000);
  };

  const triggerAutoSave = () => {
    setIsSaving(true);
    saveGame({
      totalCookies,
      buildings,
    });
    setTimeout(() => {
      setIsSaving(false);
    }, 500);
  };

  useEffect(() => {
    return () => {
      isMounted.current = false;
    };
  }, []);

  return {
    score: totalCookies,
    buildings,
    buyBuilding,
    floatingNumbers,
    spawnFloatingNumber,
    handleClick,
    cookiesPerSecond,
    elapsedSeconds,
    isPulsing,
    isSaving
  };
}

:root {
  --primary-blue: #2b8cc9;
  --text-white: #ffffff;
  --accent-gold: #f1c40f;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background: #2c3e50;
  font-family: 'Arial, sans-serif';
  margin: 0;
  padding: 0;
  min-height: 100vh;
}

.app-container {
  display: flex;
  flex-direction: column;
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;
  background: #34495e;
  border-radius: 10px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.3);
}

/* Responsive design adjustments */
@media (max-width: 768px) {
  .app-container {
    padding: 15px;
    max-width: 100%;
  }

  .cookie-button {
    width: 120px;
    height: 120px;
    font-size: 48px;
  }

  .game-header {
    flex-direction: column;
    text-align: center;
    gap: 10px;
  }

  .game-footer {
    padding: 15px;
  }
}

@media (max-width: 480px) {
  .app-container {
    padding: 10px;
  }

  .cookie-button {
    width: 100px;
    height: 100px;
    font-size: 36px;
  }

  .game-header {
    padding: 10px;
  }
}

.game-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 15px;
  background: #2980b9;
  border-radius: 8px;
  color: white;
}

.cookie-button {
  width: 150px;
  height: 150px;
  font-size: 60px;
  cursor: pointer;
  transition: transform 0.1s ease-in-out;
  display: flex;
  justify-content: center;
  align-items: center;
  border-radius: 50%;
  background: #f39c12;
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.3);
  margin: 20px auto;
}

/* Active state scaling effect */
.cookie-button:active {
  transform: scale(0.95);
}

/* Focus-visible styles for accessibility */
.cookie-button:focus-visible,
.shop-button:focus-visible {
  outline: 3px solid var(--accent-gold);
  outline-offset: 2px;
  border-radius: 50%;
}

/* Hover transition for shop buttons */
.shop-button:hover {
  background-color: #e67e22;
  transition: background-color 0.2s ease-in-out;
}

.cookie-image {
  font-size: 50px;
  display: flex;
  justify-content: center;
  align-items: center;
}

.floating-number {
  position: absolute;
  font-size: 1.5rem;
  font-weight: bold;
  color: #ffffff;
  text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
  pointer-events: none;
  user-select: none;
  will-change: opacity;
  animation: floatUp 1s ease-out forwards;
}

@keyframes floatUp {
  0% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
  50% {
    transform: translateY(-20px) scale(1.1);
  }
  100% {
    opacity: 0;
    transform: translateY(-40px) scale(1);
  }
}

/* Pulse animation for score display */
