export function formatNumber(num) {
  return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

export function formatTime(seconds) {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
}

export function saveGame(state) {
  try {
    const envelope = {
      version: 1,
      timestamp: Date.now(),
      data: state
    };
    localStorage.setItem('cookieClickerSave', JSON.stringify(envelope));
  } catch (error) {
    console.warn('Failed to save game:', error);
  }
}

export function loadGame() {
  try {
    const saved = localStorage.getItem('cookieClickerSave');
    if (!saved) return { totalCookies: 0, buildings: [] };

    const parsed = JSON.parse(saved);

    if (parsed.version === 1 && parsed.data) {
      return parsed.data;
    }

    return { totalCookies: 0, buildings: [] };
  } catch (error) {
    console.warn('Failed to load game:', error);
    return { totalCookies: 0, buildings: [] };
  }
}

